class CustomContinuationInterceptorTest : TestBase() {

    @Test
    fun testCoroutineDispatcherNotSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(Dispatchers.Default, suspend = false)

    @Test
    fun testCoroutineDispatcherSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(Dispatchers.Default, suspend = true)

    @Test
    fun testCustomContinuationInterceptorSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(
            CustomContinuationInterceptor(Dispatchers.Default),
            suspend = true
        )

    @Test
    fun testCustomContinuationInterceptorNotSuspendingDoesNotLeakCoroutineContext() =
        ensureCoroutineContextGCed(
